37	
38	declare const MAIN_WINDOW_VITE_DEV_SERVER_URL: string | undefined;
39	
40	const ALLOWED_EXTERNAL_PROTOCOLS = new Set(["http:", "https:", "mailto:"]);
41	
42	function currentThemeVariant(): SystemThemeVariant {
43	  return nativeTheme.shouldUseDarkColors ? "dark" : "light";
44	}
45	
46	function buildContentSecurityPolicy(): string {
47	  const appOrigin = getRuntimeConfig().appOrigin;
48	
49	  const devServer = MAIN_WINDOW_VITE_DEV_SERVER_URL;
50	  if (devServer) {
51	    const origin = new URL(devServer).origin;
52	    const wsOrigin = origin.replace(/^http/, "ws");
53	    return [
54	      `default-src 'self' ${origin}`,
55	      `script-src 'self' 'unsafe-inline' ${origin}`,
56	      `style-src 'self' 'unsafe-inline' ${origin}`,
57	      `connect-src 'self' ${origin} ${wsOrigin} ${appOrigin}`,
58	      `img-src 'self' data: blob: ${origin}`,
59	      `font-src 'self' data: ${origin}`,
60	    ].join("; ");
61	  }
62	  return [
63	    "default-src 'self'",
64	    "script-src 'self'",
65	    "style-src 'self' 'unsafe-inline'",
66	    `connect-src 'self' ${appOrigin}`,
67	    "img-src 'self' data: blob:",
68	    "font-src 'self' data:",
69	  ].join("; ");
70	}
71	
72	function applyContentSecurityPolicy(): void {
73	  const csp = buildContentSecurityPolicy();
74	  session.defaultSession.webRequest.onHeadersReceived((details, callback) => {
75	    callback({
76	      responseHeaders: {
77	        ...details.responseHeaders,
78	        "Content-Security-Policy": [csp],
79	      },
80	    });
81	  });
82	}
83	
84	function hardenContents(contents: Electron.WebContents): void {
85	  contents.setWindowOpenHandler(({ url }) => {
86	    try {
87	      const parsed = new URL(url);
88	      if (ALLOWED_EXTERNAL_PROTOCOLS.has(parsed.protocol)) {
89	        void shell.openExternal(url);
90	      }
91	    } catch {
92	      // ignore malformed urls
93	    }
94	    return { action: "deny" };
95	  });
96	
97	  contents.on("will-navigate", (event, url) => {
98	    const rendererOrigin = MAIN_WINDOW_VITE_DEV_SERVER_URL
99	      ? new URL(MAIN_WINDOW_VITE_DEV_SERVER_URL).origin
100	      : null;
101	    try {
102	      const target = new URL(url);
103	      if (rendererOrigin && target.origin === rendererOrigin) {
104	        return;
105	      }
106	      if (target.protocol === "file:") {
107	        return;
108	      }
109	      event.preventDefault();
110	      if (ALLOWED_EXTERNAL_PROTOCOLS.has(target.protocol)) {
111	        void shell.openExternal(url);
112	      }
113	    } catch {
114	      event.preventDefault();
115	    }
116	  });
117	}
118	
119	function registerIpcHandlers(): void {
120	  ipcMain.on(IpcChannels.getBuildInfoSync, (event) => {
121	    event.returnValue = getBuildInfo();
122	  });
123	
124	  ipcMain.on(IpcChannels.getSentryInitOptionsSync, (event) => {
125	    event.returnValue = getSentryInitOptions();
126	  });
127	
128	  ipcMain.on(IpcChannels.getSettingsSync, (event) => {
129	    event.returnValue = getSettings();
130	  });
131	
132	  ipcMain.on(IpcChannels.runtimeConfigSync, (event) => {
133	    event.returnValue = getRuntimeConfig();
134	  });
135	
136	  ipcMain.handle(IpcChannels.updateSetting, (_event, payload: unknown) => {
137	    if (!payload || typeof payload !== "object") {
138	      return getSettings();
139	    }
140	    const { key, value } = payload as {
141	      key: keyof SettingsSnapshot;
142	      value: SettingsSnapshot[keyof SettingsSnapshot];
143	    };
144	    if (!(key in getSettings())) {
145	      return getSettings();
146	    }
147	    return updateSetting(key, value);
148	  });
149	
150	  ipcMain.handle(
151	    IpcChannels.getSystemThemeVariant,
152	    (): SystemThemeVariant => currentThemeVariant()
153	  );
154	
155	  ipcMain.handle(IpcChannels.openExternal, async (_event, url: unknown) => {
156	    if (typeof url !== "string") {
157	      return;
158	    }
159	    try {
160	      const parsed = new URL(url);
161	      if (ALLOWED_EXTERNAL_PROTOCOLS.has(parsed.protocol)) {
162	        await shell.openExternal(url);
163	      }
164	    } catch {
165	      // ignore malformed urls
166	    }
167	  });
168	
169	  ipcMain.on(IpcChannels.rendererError, (_event, payload: unknown) => {
170	    // eslint-disable-next-line no-console
171	    console.error("[renderer]", payload);
172	  });
173	
174	  ipcMain.handle(IpcChannels.openWindow, async (_event, kind: unknown) => {
175	    if (kind === "secondary") {
176	      await openSecondaryWindow();
177	    } else if (kind === "hud") {
178	      await openHudWindow();
179	    } else if (kind === "primary") {
180	      await openPrimaryWindow();
