42	  name: AcceleratorName,
43	  label: string
44	): MenuItemConstructorOptions {
45	  return {
46	    label,
47	    accelerator: ACCELERATORS[name],
48	    click: () => sendMenuAction(name),
49	  };
50	}
51	
52	export interface MenuActions {
53	  openHud: () => void;
54	  openSecondary: () => void;
55	}
56	
57	export function buildApplicationMenu(actions: MenuActions): Menu {
58	  const strings = resolveLocale();
59	  const appName = app.getName();
60	  const t = (key: LocaleKeys, vars?: Record<string, string>) =>
61	    translate(strings, key, { appName, ...(vars ?? {}) });
